"use strict";(self.webpackChunkperf_agent_doc=self.webpackChunkperf_agent_doc||[]).push([["9"],{9758(t){t.exports=JSON.parse('{"version":{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"tutorialSidebar":[{"type":"link","href":"/Waynautic-Perf-Agent/","label":"Introduction to Perf Agent","docId":"intro","unlisted":false},{"type":"link","href":"/Waynautic-Perf-Agent/auto-script/","label":"Auto Script","docId":"auto-script/auto-script","unlisted":false},{"type":"link","href":"/Waynautic-Perf-Agent/auto-analysis/","label":"Auto Analysis","docId":"auto-analysis/auto-analysis","unlisted":false},{"type":"link","href":"/Waynautic-Perf-Agent/auto-nfr/","label":"NFR Strategy Hub","docId":"auto-nfr/nfr","unlisted":false},{"type":"link","href":"/Waynautic-Perf-Agent/chatbot/","label":"AI Chatbot","docId":"chatbot/chatbot","unlisted":false},{"type":"link","href":"/Waynautic-Perf-Agent/settings/","label":"Settings","docId":"settings/settings","unlisted":false}]},"docs":{"auto-analysis/auto-analysis":{"id":"auto-analysis/auto-analysis","title":"Auto Analysis","description":"Auto Analysis manages the full test execution and reporting cycle within Perf Agent. Upload your JMX script to BlazeMeter, trigger test runs through a connected GitHub or Azure DevOps pipeline, monitor results inside Perf Agent, and automatically send result reports to stakeholders by email \u2014 all from one place.","sidebar":"tutorialSidebar"},"auto-nfr/nfr":{"id":"auto-nfr/nfr","title":"NFR Strategy Hub","description":"The NFR Strategy Hub uses AI to generate a complete Non-Functional Requirements (NFR) strategy for your application. It defines your SLAs, workload model, recommended test types, and performance thresholds \u2014 giving your team a documented baseline before performance testing begins.","sidebar":"tutorialSidebar"},"auto-script/auto-script":{"id":"auto-script/auto-script","title":"Auto Script","description":"Auto Script is the script generation engine within Perf Agent. It takes two browser-recorded HAR files and produces a fully structured JMeter (.jmx) script \u2014 complete with correlation, timers, assertions, and parameterization \u2014 removing the need to build test scripts manually from scratch.","sidebar":"tutorialSidebar"},"chatbot/chatbot":{"id":"chatbot/chatbot","title":"AI Chatbot","description":"Every screen in Perf Agent includes a built-in AI chatbot, accessible via the chat icon in the bottom-right corner of the interface. It has full context of the platform \u2014 your builds, scripts, NFR strategies, bugs, and integrations \u2014 and can answer questions, surface insights, and help you navigate results without leaving your current screen.","sidebar":"tutorialSidebar"},"intro":{"id":"intro","title":"Introduction to Perf Agent","description":"Perf Agent is an intelligent performance testing platform built by Waynautic. It automates the most time-consuming parts of the performance engineering lifecycle \u2014 from generating test scripts to executing tests, analysing results, and defining the non-functional requirements that guide your entire performance strategy.","sidebar":"tutorialSidebar"},"settings/settings":{"id":"settings/settings","title":"Settings","description":"Settings is the global configuration layer for Perf Agent. Everything configured here applies across the entire platform \u2014 Auto Script, Auto Analysis, and NFR Strategy Hub all draw from the same settings, so you configure your applications, integrations, and AI models once and they are available everywhere.","sidebar":"tutorialSidebar"}}}}')}}]);